// 1. Jalamos TODO el objeto completo directamente desde el nodo llamado "Webhook Telegram Central"
const webhookData = JSON.parse(JSON.stringify($node["Webhook Telegram Central"].json));

// Capturamos el token generado por el nodo anterior de forma segura
const token = $input.first().json.linkToken || '';

// Buscamos el ID de Telegram de forma segura dentro de la estructura original
webhookData.user_id = $('Busca Empresa').first().json.id;

// 2. Validamos y estructuramos el texto del mensaje de forma segura
if (webhookData.body && webhookData.body.message) {
  const currentText = (webhookData.body.message.text || '').trim();

  // Condición: Si el texto actual ya empieza con /start, le pegamos el token dinámico
  if (currentText.startsWith('/start')) {
    // Si el usuario solo escribió "/start", lo unimos limpiamente con el token
    if (currentText === '/start') {
      webhookData.body.message.text = `/start ${token}`.trim();
    } else {
      // Si ya traía algo más, lo mantenemos y le sumamos el token al final
      webhookData.body.message.text = `${currentText} ${token}`.trim();
    }
  } else {
    // Si mandó el nombre de una tienda (ej: "mitiendavirtualpuntocl") o cualquier otra cosa,
    // ignoramos ese texto y forzamos el comando de inicio estructurado con el token dinámico
    webhookData.body.message.text = `/start ${token}`.trim();
  }
}

// 3. Retornamos TODO el JSON del webhook intacto con la modificación realizada
return [
  {
    json: webhookData
  }
];

// 1. Forzamos la lectura directa desde el nodo "Webhook Telegram Central"
const webhookData = $node["Webhook Telegram Central"].json || {};

const body = webhookData.body || {};
const message = body.message || {};

// Extraemos de forma segura el ID de Telegram del usuario (desde message.from o message.chat)
const userId = (message.from && message.from.id) || (message.chat && message.chat.id) || null;

if (!userId) {
  throw new Error('No se pudo encontrar el ID de usuario en el Webhook de Telegram.');
}

// Extraemos lo que escribió el usuario por si necesitas guardarlo (ej: "mitiendavirtualpuntocl")
const storeText = (message.text || '').trim();

// 2. Función para generar el bloque aleatorio (Hexadecimal de 48 caracteres)
const randomHex = (size) => 
  Array.from({ length: size }, () => Math.floor(Math.random() * 16).toString(16)).join('');

// 3. Generamos el token único y calculamos la expiración (10 minutos desde ahora)
const linkToken = `${randomHex(48)}${Date.now().toString(16)}`;
const expiresAt = new Date(Date.now() + 10 * 60 * 1000).toISOString();

// 4. Retornamos el payload limpio listo para insertar en tu tabla de Supabase
return [
  {
    json: {
      user_id: String(userId),     // El ID de Telegram de Felipe (7612723970)
      texto_enviado: storeText,    // El texto que ingresó ("mitiendavirtualpuntocl")
      linkToken: linkToken,        // El token seguro generado por código
      expiresAt: expiresAt         // Fecha y hora de expiración en formato ISO
    }
  }
];
